insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:2-2-demand:exam:877bc64a', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q18", "question": "The demand for a firm''s product is price inelastic. Which of the following statements must be true?", "options": ["A decrease in price will lead to excess supply", "A decrease in price will reduce the quantity sold", "An increase in price will decrease profits", "An increase in price will increase revenue"], "hint": "The revenue rule: inelastic demand means quantity barely falls when price rises — so what MUST happen to price × quantity?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — An increase in price will increase revenue</strong></p>\n<ul>\n<li>With inelastic demand the % fall in quantity is smaller than the % rise in price, so total revenue must rise.</li>\n<li>B contradicts the law of demand; A and C do not follow from inelasticity.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:943f1bb4', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q19", "question": "The table shows the relationship between the price of a good and the quantity demanded. Which of the following statements is correct?", "options": ["It shows that less is demanded when incomes rise", "It shows that price and quantity demanded are inversely related", "It shows that price elasticity of demand is equal to 1", "It shows that the equilibrium price must be £20"], "caseStudy": "<table style=\"width:100%;max-width:340px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Price (£)</th><th style=\"padding:6px;\">Quantity demanded (units)</th></tr>\n<tr><td style=\"padding:6px;\">10</td><td>80</td></tr>\n<tr><td style=\"padding:6px;\">20</td><td>70</td></tr>\n<tr><td style=\"padding:6px;\">30</td><td>60</td></tr>\n<tr><td style=\"padding:6px;\">40</td><td>50</td></tr>\n</table>", "hint": "As price goes UP the column, quantity goes DOWN. What is that relationship called? (There''s no income or supply data, so two options are impossible.)", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: B — It shows that price and quantity demanded are inversely related</strong></p>\n<ul>\n<li>Every £10 price rise cuts quantity demanded — price up, quantity down: an inverse relationship (the law of demand).</li>\n<li>There is no income data (A), the % changes are not equal so PED ≠ 1 (C), and equilibrium needs a supply schedule too (D).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:fb634cc0', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q20", "question": "The demand for apples is the amount of them that consumers are willing and able to buy at a given...", "options": ["cost", "income", "price", "supply"], "hint": "Finish the textbook definition: willing and able to buy at a given ______ in a given time period.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — price</strong></p>\n<ul>\n<li>The definition of demand: the amount consumers are willing and able to buy at a given PRICE, in a given period of time.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:6d66d8eb', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q21", "question": "Which of the following is likely to lead to an increase in the demand for air travel?", "options": ["A fall in consumer incomes", "A fall in the price of cars", "An increase in the price of air travel", "An increase in the popularity of overseas holidays"], "hint": "Overseas holidays and air travel are bought together — complements. And remember, air travel''s OWN price can''t shift its demand curve.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — An increase in the popularity of overseas holidays</strong></p>\n<ul>\n<li>Overseas holidays are a complement to air travel — more holidays demanded means more flights demanded at every price.</li>\n<li>Lower incomes (A) and cheaper substitutes (B) would cut demand; C is air travel''s own price — a movement along, not an increase in demand.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:9cae573a', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q22", "question": "Which of the diagrams above shows a demand curve which is perfectly price elastic?", "options": ["W", "X", "Y", "Z"], "caseStudy": "<img src=\"/images/economics/2-2-elasticity-curves-wxyz-extracted.png\" alt=\"Four diagrams from the OCR exam paper, each with Price and Quantity axes: W is a downward-sloping line, X is a horizontal line, Y is an upward-sloping line, Z is a vertical line\" style=\"display:block;width:100%;max-width:560px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Perfectly ELASTIC = horizontal (any quantity at one price). Perfectly INELASTIC = vertical. Don''t mix them up!", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b, Quantitative skills)</h5>\n<p><strong>Answer: B — X</strong></p>\n<ul>\n<li>A perfectly price elastic demand curve is horizontal — consumers will buy any amount at that one price, and nothing at any higher price.</li>\n<li>Z (vertical) is perfectly INELASTIC; W is an ordinary demand curve; Y slopes upwards like a supply curve.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:d2a30e16', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q24", "question": "A market starts in equilibrium and then demand falls. Which of the following is most likely to happen?", "options": ["A higher equilibrium price and equilibrium quantity", "A higher equilibrium price and lower equilibrium quantity", "A lower equilibrium price and equilibrium quantity", "A lower equilibrium price and higher equilibrium quantity"], "hint": "Picture the diagram: demand shifts LEFT along an unchanged supply curve. The new crossing point is lower and further left — so price and quantity both...?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — A lower equilibrium price and equilibrium quantity</strong></p>\n<ul>\n<li>A leftward demand shift moves the equilibrium down the supply curve: both price and quantity fall.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:c9e1dcaa', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q25", "question": "The demand curve for strawberries will shift to the left if there is...", "options": ["a fall in the price of raspberries", "a fall in the price of strawberries", "a rise in the price of raspberries", "a rise in the price of strawberries"], "caseStudy": "<p>Raspberries and strawberries are substitute goods.</p>", "hint": "Strawberries'' own price can never SHIFT the strawberry demand curve. For a LEFT shift, buyers must be lured away — what makes raspberries more tempting?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — a fall in the price of raspberries</strong></p>\n<ul>\n<li>Cheaper raspberries pull shoppers away from strawberries — fewer strawberries demanded at every price, shifting the curve left.</li>\n<li>B and D are strawberries'' own price (movements along); C would shift strawberry demand RIGHT.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:3c9705ff', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q26", "question": "What will usually lead to a shift in the demand curve to the right?", "options": ["An increase in consumers'' incomes", "A technological improvement which reduces the costs of production", "The government introduces a tax on the product", "The supply curve shifts to the right"], "hint": "Three of these change SUPPLY (costs, tax, the supply curve itself). Only one is a demand-side factor.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — An increase in consumers'' incomes</strong></p>\n<ul>\n<li>Higher incomes mean more demanded at every price — a rightward demand shift.</li>\n<li>B, C and D all act on the supply side; a supply shift moves the market ALONG the demand curve.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:fe003030', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q27", "question": "Which of the following will occur if there is a large increase in the demand for housing?", "options": ["A leftward shift in the demand curve for builders", "A leftward shift in the supply curve of builders", "A rightward shift in the demand curve for builders", "A rightward shift in the supply curve of builders"], "hint": "Builders are wanted BECAUSE houses are wanted — derived demand. More houses demanded means what for the demand for builders?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — A rightward shift in the demand curve for builders</strong></p>\n<ul>\n<li>The demand for builders is DERIVED from the demand for housing — more houses wanted means more builders demanded at every wage.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:d3798ee9', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q28", "question": "The diagram shows the market for rented accommodation. Which of the following statements about the diagram is correct?", "options": ["A price of r is above the market price of rented accommodation", "As the price of rented accommodation increases supply will increase", "If r is the current price of rented accommodation some people will not be able to rent any accommodation", "The supply of rented accommodation is price elastic"], "caseStudy": "<img src=\"/images/economics/2-2-rented-accommodation-extracted.png\" alt=\"Diagram from the OCR exam paper: the market for rented accommodation with a downward-sloping demand curve D, a vertical supply curve S, and a price r marked with a dashed line below the point where the curves cross\" style=\"display:block;width:100%;max-width:460px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "r sits BELOW the equilibrium — so demand exceeds the fixed (vertical = perfectly inelastic) supply. What does excess demand mean for some would-be renters?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — If r is the current price of rented accommodation some people will not be able to rent any accommodation</strong></p>\n<ul>\n<li>At price r (below equilibrium) quantity demanded exceeds the fixed supply — excess demand — so some renters go without.</li>\n<li>The vertical supply curve is perfectly INELASTIC, so B and D are wrong; r is BELOW the market price, so A is wrong.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:bf8659c7', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q29", "question": "The diagram shows the demand curve for a good. Which area represents the total amount paid by consumers when the price is A?", "options": ["AEB", "OABC", "OABD", "OEBC"], "caseStudy": "<img src=\"/images/economics/2-2-total-spending-area-extracted.png\" alt=\"Diagram from the OCR exam paper: a demand curve falling from point E on the price axis to point D on the quantity axis, with price A marked, meeting the curve at point B above quantity C, and the origin labelled O\" style=\"display:block;width:100%;max-width:420px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Total spending = price × quantity = the RECTANGLE with height OA (the price) and width OC (the quantity bought at that price).", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: B — OABC</strong></p>\n<ul>\n<li>Total spending = price × quantity: the rectangle from the origin O up to price A, across to point B on the curve, and down to quantity C.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:077a3688', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q30", "question": "The price elasticity of demand for a good is unitary. What will happen if prices rise?", "options": ["Expenditure on the good will fall", "Expenditure on the good will rise", "The quantity demanded will fall", "The quantity demanded will rise"], "hint": "Unitary means the % fall in quantity exactly matches the % rise in price — so total spending stays the SAME. What does still change?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — The quantity demanded will fall</strong></p>\n<ul>\n<li>With unitary PED, expenditure stays constant when price changes (A and B wrong) — but the law of demand still applies: a price rise cuts quantity demanded.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:16489965', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q33", "question": "A flower seller increases her prices by 10% and finds that it has no effect on the amount that she sells. This suggests that demand for the flowers is...", "options": ["perfectly price elastic", "perfectly price inelastic", "price inelastic", "unitary price elastic"], "hint": "NO effect at all — quantity doesn''t change even slightly. That''s stronger than ordinary inelastic (a small change). PED = 0 ÷ 10 = 0.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — perfectly price inelastic</strong></p>\n<ul>\n<li>Zero change in quantity for a 10% price rise means PED = 0 — PERFECTLY price inelastic (a vertical demand curve).</li>\n<li>Ordinary price inelastic (C) would still show a small fall in sales.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:5ae4f8f7', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q35", "question": "Demand is defined as...", "options": ["the desire to purchase a good or service over time", "the relationship between the quantity of a good or service sold and consumer incomes", "the relationship between the total revenue a firm receives and the price", "the willingness and ability to purchase a good or service"], "hint": "Desire alone is NOT demand — you must also be able to pay. Which option has both halves?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — the willingness and ability to purchase a good or service</strong></p>\n<ul>\n<li>Demand needs BOTH willingness AND ability to pay. A is desire only; B and C describe different relationships entirely.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:ea238cb5', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q36", "question": "Which of the following is the most likely effect of an increase in advertising on the market for breakfast cereals?", "options": ["The market demand curve shifts to the left", "The market demand curve shifts to the right", "The market supply curve shifts to the left", "The market supply curve shifts to the right"], "hint": "Advertising is one of the classic demand shift factors — it makes MORE people want cereal at every price.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — The market demand curve shifts to the right</strong></p>\n<ul>\n<li>Successful advertising raises willingness to buy at every price — a rightward shift of market demand. It acts on buyers, not on production costs, so supply is unaffected.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:20bd3d81', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q37", "question": "Excess demand is corrected in a market by changes in...", "options": ["price", "quantity", "resource allocation", "taxes"], "hint": "Too many buyers chasing too few goods — what rises to ration the shortage and signal producers to supply more?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — price</strong></p>\n<ul>\n<li>Excess demand pushes the price UP, which chokes off some demand and encourages more supply until the market clears — the price mechanism at work.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:exam:ec782ba9', 'economics', 'economics:2-2-demand', '2.2 Demand', 'exam', 'mcq', 1, '{"num": "Q38", "question": "Market demand is the total demand for goods and services as a result of...", "options": ["adding together all individual demand", "adding together direct and indirect demand", "changes in prices at each quantity", "consumers'' willingness and ability to buy"], "hint": "Market demand = every consumer''s demand summed up. One option says exactly that.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — adding together all individual demand</strong></p>\n<ul>\n<li>Market demand is the sum of all individual demands at each price — the Diagram Z idea from earlier in this paper.</li>\n<li>D describes demand itself, not how MARKET demand is built from individual demands.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Many candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-2-demand:mcq:7b4229f4', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Which of the following is the correct definition of demand?", "options": ["The willingness and ability to buy a good or service at a given price in a given time period", "The total money spent on a good", "The amount of a good producers offer for sale", "The desire to own a good or service"]}'::jsonb, '{"answer": 0, "explain": "Demand needs BOTH willingness and ability, at a given price, in a given time period. Desire alone is not demand — you must be able to pay."}'::jsonb),
('economics:2-2-demand:mcq:4e53e1e8', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Which of the following causes a movement ALONG the demand curve for chocolate (not a shift)?", "options": ["A fall in the price of chocolate itself", "A successful advertising campaign", "A rise in consumers'' incomes", "A health scare about sugar"]}'::jsonb, '{"answer": 0, "explain": "Only a change in the good''s OWN price causes a movement along the curve. Income, advertising and tastes all shift the whole curve."}'::jsonb),
('economics:2-2-demand:mcq:608f6007', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Consumers'' incomes rise. What happens in the market for cinema tickets (a normal good)?", "options": ["A movement down the demand curve", "The supply curve shifts right", "Demand shifts right", "Demand shifts left"]}'::jsonb, '{"answer": 2, "explain": "Higher incomes mean people can afford more trips to the cinema at every price — the whole demand curve shifts right."}'::jsonb),
('economics:2-2-demand:mcq:119f4857', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "A firm raises its price by 10% and quantity demanded falls by 5%. PED (ignoring the sign) is...", "options": ["15, so demand is perfectly elastic", "2, so demand is price elastic", "0.5, so demand is price elastic", "0.5, so demand is price inelastic"]}'::jsonb, '{"answer": 3, "explain": "PED = %ΔQd ÷ %ΔP = 5 ÷ 10 = 0.5. Less than 1 means quantity responds less than price — price inelastic."}'::jsonb),
('economics:2-2-demand:mcq:d4f24e2a', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Demand for a product is price elastic. To increase total revenue the business should...", "options": ["Raise the price", "Keep the price the same", "Cut the price", "Reduce output"]}'::jsonb, '{"answer": 2, "explain": "With elastic demand, cutting the price wins proportionally MORE customers, so total revenue (price × quantity) rises."}'::jsonb),
('economics:2-2-demand:mcq:c8b21ac2', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Petrol and electric cars are substitutes. A large rise in the price of petrol is most likely to...", "options": ["Shift the demand curve for electric cars right", "Shift the demand curve for electric cars left", "Cause a movement along the electric car demand curve", "Shift the supply of electric cars left"]}'::jsonb, '{"answer": 0, "explain": "When one substitute gets dearer, buyers switch to the other — demand for electric cars rises at every price, a rightward shift."}'::jsonb),
('economics:2-2-demand:mcq:a61ee492', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Printers and ink cartridges are complements. If the price of printers falls sharply, demand for ink cartridges will...", "options": ["Shift right", "Shift left", "Become perfectly inelastic", "Stay exactly the same"]}'::jsonb, '{"answer": 0, "explain": "Cheaper printers → more printers bought → more ink needed at every price. Complements move together, so cartridge demand shifts right."}'::jsonb),
('economics:2-2-demand:mcq:e18c98e7', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "A perfectly price inelastic demand curve is drawn as...", "options": ["A horizontal line", "An upward-sloping line", "A vertical line", "A 45-degree line"]}'::jsonb, '{"answer": 2, "explain": "Perfectly inelastic (PED = 0) means quantity never changes whatever the price — a vertical line. Perfectly elastic is the horizontal one."}'::jsonb),
('economics:2-2-demand:mcq:b7b05a08', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Governments put high taxes on cigarettes and fuel mainly because demand for them is...", "options": ["Price elastic, so people stop buying", "Perfectly elastic, so firms pay the tax", "Price inelastic, so people keep buying and tax revenue is reliable", "Unitary, so revenue never changes"]}'::jsonb, '{"answer": 2, "explain": "Few substitutes make demand inelastic — quantity barely falls when tax raises the price, so the government collects reliable revenue."}'::jsonb),
('economics:2-2-demand:mcq:d7f7ca96', 'economics', 'economics:2-2-demand', '2.2 Demand', 'mcq', 'mcq', 1, '{"question": "Which of the following is the best example of derived demand?", "options": ["Demand for plums rising when apples get dearer", "Demand for ice cream rising in summer", "Demand for bricklayers rising because demand for new houses has risen", "Demand for luxury goods rising with incomes"]}'::jsonb, '{"answer": 2, "explain": "Derived demand is demand that comes FROM the demand for something else — workers are wanted because the products they make are wanted."}'::jsonb),
('economics:2-2-demand:tf:1f9b7382', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "Demand simply means wanting a good or service."}'::jsonb, '{"answer": false, "explain": "Demand is the willingness AND ability to buy, at a given price, in a given time period. Wanting something you cannot afford is not demand."}'::jsonb),
('economics:2-2-demand:tf:afdb9dc2', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "A fall in the price of a good causes its demand curve to shift to the right."}'::jsonb, '{"answer": false, "explain": "A change in the good''s own price causes a MOVEMENT ALONG the curve (an expansion), not a shift. Only non-price factors shift the curve."}'::jsonb),
('economics:2-2-demand:tf:19f33ebb', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "Market demand is found by adding together all the individual demands."}'::jsonb, '{"answer": true, "explain": "Correct — at each price, add up what every consumer would buy. The real exam showed this as Diagram Z: Consumers A+B combined."}'::jsonb),
('economics:2-2-demand:tf:ddce6c52', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "If PED is greater than 1 (ignoring the minus sign), demand is price elastic."}'::jsonb, '{"answer": true, "explain": "PED > 1 means the % change in quantity demanded is bigger than the % change in price — that is the definition of price elastic."}'::jsonb),
('economics:2-2-demand:tf:8b26d106', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "If demand is price inelastic, a firm can increase its total revenue by raising its price."}'::jsonb, '{"answer": true, "explain": "Quantity barely falls when price rises, so price × quantity goes up. This is the revenue rule — inelastic → raise price."}'::jsonb),
('economics:2-2-demand:tf:9b53fb38', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "A steep demand curve shows price elastic demand."}'::jsonb, '{"answer": false, "explain": "It''s the other way round: steep = inelastic (quantity barely responds), flat = elastic. Perfectly inelastic is vertical; perfectly elastic is horizontal."}'::jsonb),
('economics:2-2-demand:tf:392cfb9f', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "An increase in advertising is likely to shift the market demand curve to the right."}'::jsonb, '{"answer": true, "explain": "Successful marketing makes more people want the product at every price — a rightward shift. This was a real exam MCQ about breakfast cereals."}'::jsonb),
('economics:2-2-demand:tf:1078a5e5', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tf', 'tf', 1, '{"question": "A perfectly price inelastic demand curve is horizontal."}'::jsonb, '{"answer": false, "explain": "Perfectly INELASTIC is vertical (quantity never changes). The horizontal curve is perfectly ELASTIC. The real exam asked exactly this with four diagrams."}'::jsonb),
('economics:2-2-demand:learn:d929da0f', 'economics', 'economics:2-2-demand', '2.2 Demand', 'learn', 'mcq', 1, '{"readingTitle": "What is demand?", "reading": "<p><strong>Demand</strong> is the <strong>willingness and ability</strong> of consumers to buy a good or service <strong>at a given price, in a given period of time</strong>.</p>\n<h4>All four parts of the definition earn marks</h4>\n<ul>\n<li><strong>Willing</strong> — you actually want it.</li>\n<li><strong>Able</strong> — you can afford to pay for it. Wanting a Ferrari is not demand!</li>\n<li><strong>At a given price</strong> — demand is always measured at a specific price.</li>\n<li><strong>In a given period of time</strong> — e.g. per week or per month. Examiners take a mark off if you miss price or time.</li>\n</ul>\n<h4>Individual, market and derived demand</h4>\n<ul>\n<li><strong>Individual demand</strong> — the demand of one single consumer.</li>\n<li><strong>Market demand</strong> — <strong>all the individual demands added together</strong>. If Consumer A buys 3 and Consumer B buys 5 at £10, market demand at £10 is 8.</li>\n<li><strong>Derived demand</strong> — demand that comes from the demand for something else. Builders are demanded because <em>houses</em> are demanded; workers are demanded because the <em>products they make</em> are demanded.</li>\n</ul>\n<h4>The law of demand and the demand curve</h4>\n<ul>\n<li>As <strong>price falls, quantity demanded rises</strong> (and vice versa) — price and quantity demanded are <strong>inversely related</strong>.</li>\n<li>The demand curve slopes <strong>downwards from left to right</strong>.</li>\n<li>Always label it: <strong>Price</strong> on the vertical axis, <strong>Quantity</strong> on the horizontal axis, and <strong>D</strong> on the curve. An unlabelled diagram scores no marks.</li>\n</ul>", "question": "Market demand is found by...", "options": ["Adding together all the individual demands", "Taking the biggest individual demand", "Multiplying price by quantity", "Asking producers how much they want to sell"]}'::jsonb, '{"answer": 0, "explain": "Market demand = all individual demands added together at each price. That''s why Diagram Z (Consumers A+B) in the real exam shows the two individual curves combined."}'::jsonb),
('economics:2-2-demand:learn:22b92194', 'economics', 'economics:2-2-demand', '2.2 Demand', 'learn', 'mcq', 1, '{"readingTitle": "Movements along vs shifts of the demand curve", "reading": "<p>This is one of the most heavily tested ideas in the whole course. The rule is simple:</p>\n<h4>Movement ALONG the curve — caused ONLY by the good''s own price</h4>\n<ul>\n<li>Price falls → quantity demanded rises → movement <strong>down</strong> the curve. This is an <strong>expansion</strong> (or extension) of demand.</li>\n<li>Price rises → quantity demanded falls → movement <strong>up</strong> the curve. This is a <strong>contraction</strong> of demand.</li>\n<li>The curve itself <strong>does not move</strong>.</li>\n</ul>\n<h4>SHIFT of the whole curve — caused by anything EXCEPT the good''s own price</h4>\n<p>More demanded at <em>every</em> price = shift <strong>right</strong> (outward). Less at every price = shift <strong>left</strong> (inward). Learn the shift factors:</p>\n<ul>\n<li><strong>Income</strong> — more income usually means more demand.</li>\n<li><strong>Marketing / advertising</strong> — successful campaigns shift demand right.</li>\n<li><strong>Taste and fashion</strong> — trends change what people want.</li>\n<li><strong>Price of substitutes</strong> — goods that replace each other (apples and plums). If the price of apples <em>rises</em>, demand for plums shifts <em>right</em>.</li>\n<li><strong>Price of complements</strong> — goods bought together (consoles and games). If the price of consoles <em>rises</em>, demand for games shifts <em>left</em>.</li>\n<li><strong>Population</strong> — more (or different) people, more demand.</li>\n<li><strong>Government policies</strong> — taxes, subsidies and rules change demand.</li>\n<li><strong>The economic situation</strong> — booms raise demand, recessions cut it.</li>\n<li><strong>Price expectations</strong> — if people expect prices to rise, they buy now.</li>\n</ul>\n<h4>Consequences for consumers and producers</h4>\n<ul>\n<li>Demand shifts right → price AND quantity rise → producers earn more revenue; consumers pay more.</li>\n<li>Demand shifts left → price and quantity fall → revenue and profits fall; some firms may leave the market.</li>\n<li>A <strong>movement along</strong> the demand curve can only be caused by a <strong>shift of the supply curve</strong> changing the price.</li>\n</ul>", "question": "The price of raspberries rises. What happens in the market for strawberries (a substitute)?", "options": ["The demand curve for strawberries shifts left", "There is a movement along the strawberry demand curve", "Nothing happens", "The demand curve for strawberries shifts right"]}'::jsonb, '{"answer": 3, "explain": "Raspberries are now dearer, so some shoppers switch to strawberries — more strawberries are demanded at every price, shifting the strawberry demand curve right."}'::jsonb),
('economics:2-2-demand:learn:6f4b9f26', 'economics', 'economics:2-2-demand', '2.2 Demand', 'learn', 'mcq', 1, '{"readingTitle": "Price elasticity of demand (PED)", "reading": "<p><strong>PED measures the responsiveness of quantity demanded to a change in price.</strong></p>\n<h4>The formula</h4>\n<ul>\n<li><strong>PED = % change in quantity demanded ÷ % change in price</strong></li>\n<li>The answer is negative (price up, quantity down), so we usually <strong>ignore the minus sign</strong> and compare the size to 1.</li>\n</ul>\n<h4>The five results</h4>\n<ul>\n<li><strong>Price elastic (PED &gt; 1)</strong> — quantity responds MORE than price. Drawn as a <strong>flat</strong> curve. E.g. price falls 20%, quantity rises 50% → PED = 2.5.</li>\n<li><strong>Price inelastic (PED &lt; 1)</strong> — quantity responds LESS than price. Drawn as a <strong>steep</strong> curve. E.g. price falls 25%, quantity rises 15% → PED = 0.6.</li>\n<li><strong>Unitary (PED = 1)</strong> — quantity changes by exactly the same % as price, so total spending stays the same.</li>\n<li><strong>Perfectly price inelastic (PED = 0)</strong> — a <strong>vertical</strong> line: price changes have no effect at all on quantity.</li>\n<li><strong>Perfectly price elastic (PED = ∞)</strong> — a <strong>horizontal</strong> line: consumers buy any amount at one price only.</li>\n</ul>\n<h4>What makes demand elastic or inelastic?</h4>\n<ul>\n<li><strong>Substitutes</strong> — lots of close substitutes → elastic; few → inelastic.</li>\n<li><strong>Necessity vs luxury</strong> — necessities (fuel, medicine) → inelastic; non-essentials → more elastic.</li>\n<li><strong>Time</strong> — demand gets MORE elastic over time as people find alternatives.</li>\n<li><strong>Share of income</strong> — cheap items (chewing gum) → inelastic; expensive items → elastic.</li>\n</ul>\n<p><strong>Drawing tip:</strong> elastic and inelastic curves must have clearly different slopes (flat vs steep) and be labelled — two parallel lines score nothing.</p>", "question": "A fishmonger cuts the price of haddock by 20% and sales rise from 20 to 30 pieces (+50%). Demand is...", "options": ["Perfectly price inelastic", "Price elastic", "Unitary price elastic", "Price inelastic"]}'::jsonb, '{"answer": 1, "explain": "PED = 50% ÷ 20% = 2.5, which is bigger than 1 — price elastic. This exact calculation appeared as a real exam MCQ."}'::jsonb),
('economics:2-2-demand:learn:8931690f', 'economics', 'economics:2-2-demand', '2.2 Demand', 'learn', 'mcq', 1, '{"readingTitle": "Why PED matters — the revenue rule", "reading": "<p><strong>Total revenue = price × quantity sold.</strong> PED tells a business what happens to revenue when it changes price — that is why examiners love it.</p>\n<h4>The revenue rule</h4>\n<ul>\n<li><strong>Demand elastic → CUT the price.</strong> The % rise in quantity is bigger than the % fall in price, so revenue rises.</li>\n<li><strong>Demand inelastic → RAISE the price.</strong> Quantity barely falls, so revenue rises.</li>\n</ul>\n<h4>Worked example — the muffin stall</h4>\n<ul>\n<li>Selling 100 muffins at £1 each = £100 revenue.</li>\n<li>If demand is <strong>elastic</strong> (PED = 2): cut the price 10% to 90p → quantity rises 20% to 120 → revenue = £108. ✔</li>\n<li>If demand is <strong>inelastic</strong> (PED = 0.5): raise the price 10% to £1.10 → quantity falls only 5% to 95 → revenue = £104.50. ✔</li>\n</ul>\n<h4>Who uses PED in the real world?</h4>\n<ul>\n<li><strong>Businesses</strong> — set the price that earns the most revenue, and use <strong>price discrimination</strong> (different prices for different groups — peak vs off-peak train tickets, student discounts) when groups have different PEDs.</li>\n<li><strong>Farmers</strong> — demand for food is inelastic, so a bumper crop (big rise in supply) crashes the price and can cut farm incomes.</li>\n<li><strong>Government</strong> — taxes goods with inelastic demand (fuel, cigarettes, alcohol) because people keep buying, so tax revenue is reliable.</li>\n<li><strong>Consumers</strong> — PED matters most to buyers who choose on price; someone who cares more about quality than price will barely respond to price changes.</li>\n</ul>\n<h4>But be ready to evaluate</h4>\n<ul>\n<li>PED estimates come from guesses or small surveys — <strong>how reliable is the data?</strong></li>\n<li>Is revenue the business''s main objective, or does it want market share?</li>\n<li>Competitors can react and change the picture; PED also changes over time.</li>\n</ul>", "question": "Demand for a firm''s product is price inelastic. Which statement MUST be true?", "options": ["A decrease in price will lead to excess supply", "A decrease in price will reduce the quantity sold", "An increase in price will decrease profits", "An increase in price will increase revenue"]}'::jsonb, '{"answer": 3, "explain": "Inelastic demand means quantity barely responds, so a price rise raises total revenue. This is a real exam MCQ — and the heart of the revenue rule."}'::jsonb),
('economics:2-2-demand:misc:f62e9e3f', 'economics', 'economics:2-2-demand', '2.2 Demand', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The price of the good went up, so its demand curve shifts to the left.\"</p><p><strong>✅ The correct idea:</strong> A change in the good''s OWN price never shifts its demand curve — it causes a movement ALONG the curve (a contraction if price rises, an expansion if it falls). The curve only shifts when a NON-price factor changes: income, marketing, taste and fashion, prices of substitutes and complements, population, government policy, the economic situation or price expectations. This is one of the most heavily tested distinctions on the whole paper — and one OCR examiners see mixed up every single year.</p>", "question": "The price of restaurant meals falls. What happens to the demand curve for restaurant meals?", "options": ["There is a movement down along the curve", "It shifts left", "It becomes steeper", "It shifts right"]}'::jsonb, '{"answer": 0, "explain": "Own price changed → movement along the curve, never a shift. A rise in consumer incomes is what would shift it right (the real Q1 answer)."}'::jsonb),
('economics:2-2-demand:misc:82098d0e', 'economics', 'economics:2-2-demand', '2.2 Demand', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Demand is when people buy things.\"</p><p><strong>✅ The correct idea:</strong> Examiners award the definition marks for four specific parts: WILLING and ABLE to buy, AT A GIVEN PRICE, IN A GIVEN TIME PERIOD. On the real ''Explain what is meant by demand'' 2-marker, candidates who missed price and/or time period were capped at 1 mark, and vague constructions like ''when people buy things'' scored 0. Learn the full sentence word-for-word — it is free marks.</p>", "question": "Which answer would score full marks for ''Explain what is meant by demand''?", "options": ["The amount of money spent in shops", "How much of a good people want", "The willingness and ability to buy a good at a given price in a given time period", "When consumers buy goods and services"]}'::jsonb, '{"answer": 2, "explain": "The real OCR mark scheme awards 2 marks only when willing + able + price + time are all there. The examiner report said exactly this."}'::jsonb),
('economics:2-2-demand:misc:1b58c55d', 'economics', 'economics:2-2-demand', '2.2 Demand', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The dresses are elastic.\" / \"Haddock is inelastic.\"</p><p><strong>✅ The correct idea:</strong> Goods are not elastic — DEMAND for them is price elastic or price inelastic. OCR put an ''Assessment for Learning'' warning in a real mark scheme about this exact sloppiness: candidates who wrote ''dresses are elastic'' or ''demand falls a lot'' instead of ''demand for dresses is price elastic, so a price rise causes a proportionally larger fall in quantity demanded'' lost credit. Always name the concept in full: <em>demand for X is price elastic/inelastic</em>.</p>", "question": "Which sentence uses the terminology correctly?", "options": ["The elasticity of dresses is high", "Dresses stretch when prices change", "Demand for the dresses is price elastic", "The dresses are elastic"]}'::jsonb, '{"answer": 2, "explain": "It''s the DEMAND that is elastic, not the product. OCR flagged this exact error in the published mark scheme for the charity-shop question."}'::jsonb),
('economics:2-2-demand:misc:cadd75ba', 'economics', 'economics:2-2-demand', '2.2 Demand', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Price inelastic means nobody stops buying when the price goes up.\"</p><p><strong>✅ The correct idea:</strong> That describes PERFECTLY price inelastic demand (PED = 0, a vertical curve) — a different thing. Ordinary price inelastic demand means quantity demanded DOES fall when price rises, just by a SMALLER percentage than the price change. On the real 2-marker ''Explain what is meant by demand is price inelastic'', answers describing perfectly inelastic demand were capped at 1 mark, and answers with no reference to percentage changes usually got 1. The full-mark sentence: <em>the percentage change in quantity demanded is less than the percentage change in price</em>.</p>", "question": "Demand for a good is price inelastic (PED = 0.4). The price rises 10%. Quantity demanded...", "options": ["Does not change at all", "Falls by more than 10%", "Rises by 4%", "Falls by about 4%"]}'::jsonb, '{"answer": 3, "explain": "Inelastic means a smaller response, not NO response — 0.4 × 10% = 4% fall. ''No change at all'' is perfectly inelastic."}'::jsonb),
('economics:2-2-demand:misc:d68cbbdb', 'economics', 'economics:2-2-demand', '2.2 Demand', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Putting the price up always brings in more money.\"</p><p><strong>✅ The correct idea:</strong> It depends entirely on PED. If demand is INELASTIC, yes — quantity barely falls, so revenue rises (that is why Kasia and Ben''s window-cleaning PED of −0.2 meant they should raise price). But if demand is ELASTIC, a price rise loses proportionally MORE customers and revenue FALLS — the right move is to CUT the price, like CDS cutting delivery from £25 to £20 and gaining £1,500 a week. Always work out the elasticity first, then apply the revenue rule.</p>", "question": "Demand is price elastic. The business wants more revenue. It should...", "options": ["Raise its price", "Leave the price alone", "Reduce the quantity supplied", "Cut its price"]}'::jsonb, '{"answer": 3, "explain": "Elastic → cut price → quantity rises by a bigger % than the price fell → total revenue rises. Inelastic is the opposite."}'::jsonb),
('economics:2-2-demand:misc:13f14760', 'economics', 'economics:2-2-demand', '2.2 Demand', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"To show elastic and inelastic demand, draw two demand curves side by side.\"</p><p><strong>✅ The correct idea:</strong> Two PARALLEL demand curves show a shift in demand, not different elasticities — and OCR''s examiner report said candidates who drew parallel curves for the Celandine Hotel question lost marks. Elastic and inelastic curves must have clearly DIFFERENT slopes: the elastic curve is FLAT (flatter than 45°), the inelastic curve is STEEP, and they are usually drawn crossing each other. Then label each one — ''D1 elastic'', ''D2 inelastic'' — because a diagram the examiner has to guess at scores nothing.</p>", "question": "How should you draw an elastic and an inelastic demand curve on one diagram?", "options": ["One upward and one downward line", "Two parallel downward lines", "Two vertical lines", "One flat curve and one steep curve, crossing, each labelled"]}'::jsonb, '{"answer": 3, "explain": "Different slopes show different elasticities. Parallel curves show a shift — a different concept — and the examiner report flagged this exact mistake."}'::jsonb),
('economics:2-2-demand:tips:13f93d23', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tips', 'mcq', 1, '{"readingTitle": "definitions — The 2-markers: learn the two-part definitions word-for-word", "reading": "<p>This topic''s real papers asked for the same definitions again and again. Learn them exactly:</p>\n<ul>\n<li><strong>Demand</strong> — the willingness and ability to buy a good or service <em>at a given price, in a given period of time</em>.</li>\n<li><strong>PED</strong> — the responsiveness of quantity demanded to a change in price (1 mark for <em>responsiveness</em>, 1 mark for it being <em>quantity demanded responding to price</em> — not the other way round).</li>\n<li><strong>Price inelastic</strong> — the <em>percentage</em> change in quantity demanded is less than the <em>percentage</em> change in price.</li>\n</ul>\n<h4>How real answers scored</h4>\n<p>❌ <strong>0 marks:</strong> \"Demand is when people buy things.\" — vague, no price, no time.</p>\n<p>⚠️ <strong>1 mark:</strong> \"Demand is the willingness and ability to buy a good.\" — good start, but price and time period are missing.</p>\n<p>✅ <strong>2 marks:</strong> \"Demand is the willingness and ability to buy a good or service at a given price in a given period of time.\"</p>\n<p>The examiner report said candidates who had learned the definition reproduced it for 2 marks; those who tried to construct one on the spot usually got 0.</p>", "question": "In the PED definition, what responds to what?", "options": ["Revenue responds to costs", "Supply responds to demand", "Price responds to a change in quantity", "Quantity demanded responds to a change in price"]}'::jsonb, '{"answer": 3, "explain": "The real mark scheme gives the second mark specifically for saying quantity demanded is affected by price ''and not vice versa''."}'::jsonb),
('economics:2-2-demand:tips:3dd9807a', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tips', 'mcq', 1, '{"readingTitle": "diagrams — Drawing questions: label everything or score nothing", "reading": "<p>This paper has FOUR drawing questions. The mark schemes are brutal about labels:</p>\n<ul>\n<li>A demand curve that is <strong>unlabelled or slopes upwards scores no marks</strong> (garden business question).</li>\n<li>Elastic vs inelastic curves need clearly <strong>different slopes</strong> — flat for elastic, steep for inelastic — plus labels like \"D1 elastic / D2 inelastic\". Parallel curves lost marks (Celandine Hotel).</li>\n<li>Plotting from a table? <strong>Join the points</strong> — unjoined points were capped at 1 mark, and one wrongly plotted point also capped at 1 (charity-shop dresses).</li>\n<li>Shifting demand? Draw <strong>both</strong> curves and mark the direction — D then D1 to the right.</li>\n</ul>\n<h4>The 30-second checklist before you move on</h4>\n<ul>\n<li>Axes labelled <strong>Price</strong> and <strong>Quantity</strong>?</li>\n<li>Every curve labelled (D, D1, S...)?</li>\n<li>Downward slope for demand?</li>\n<li>Shift direction / slope difference obvious at a glance?</li>\n</ul>", "question": "You draw two perfect demand curves showing a rightward shift but forget to label them. The mark scheme says...", "options": ["Full marks anyway", "Only 1 of the 2 marks", "Zero automatically", "The examiner asks you"]}'::jsonb, '{"answer": 1, "explain": "The Celandine mark scheme: two correct curves with no appropriate labels = 1 mark. Labels are half the marks on most drawing questions."}'::jsonb),
('economics:2-2-demand:tips:46b85ae1', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Calculations: total revenue, PED and the Own Figure Rule", "reading": "<p>Three calculation types appear in this topic''s real papers:</p>\n<ul>\n<li><strong>Total revenue</strong> = price × quantity. CDS: at £25 revenue is £25 × 300 = £7,500; at £20 it is £20 × 450 = £9,000; the change is <strong>+£1,500</strong>.</li>\n<li><strong>Interest changes</strong> — 3.5% of £10,000 is £350, 2.5% is £250, so the payment rises £100.</li>\n<li><strong>PED from percentages</strong> — price cut 20%, quantity up 50% → PED = 50 ÷ 20 = 2.5 → elastic.</li>\n</ul>\n<h4>Why you ALWAYS show working</h4>\n<p>OCR uses the <strong>Own Figure Rule</strong>: if you make one slip (say, a decimal point) but your method is right, you still get 1 of the 2 marks — but only if your working is on the page.</p>\n<p>Then link the number to the revenue rule: elastic → cutting price RAISES revenue; inelastic → raising price RAISES revenue. The 6-markers expect you to USE the calculation you just did.</p>", "question": "You misplace a decimal but show correct working. Under the Own Figure Rule you get...", "options": ["1 of the 2 marks", "No marks", "Half a mark", "Both marks"]}'::jsonb, '{"answer": 0, "explain": "The real mark scheme states: ''OFR applies for a maximum of 1 mark'' — but only if the examiner can see your method."}'::jsonb),
('economics:2-2-demand:tips:969d88e4', 'economics', 'economics:2-2-demand', '2.2 Demand', 'tips', 'mcq', 1, '{"readingTitle": "sixmarker — The 6-markers: use the case study, and evaluate means judge", "reading": "<p>This topic''s 6-markers split into <strong>Analyse</strong> (chains of reasoning, no conclusion needed) and <strong>Evaluate</strong> (both sides + a supported judgement). The examiner reports show exactly where candidates lose marks:</p>\n<h4>How real answers scored</h4>\n<p>❌ <strong>Level 0–1 (1–2 marks):</strong> A pre-prepared answer about competition in general, never mentioning gardens, cafés or delivery parcels. \"Many candidates could not access more than three marks as they included no link to the extract.\"</p>\n<p>⚠️ <strong>Level 2 (3–4 marks):</strong> Correct single effects — \"revenue falls, profits fall\" — but not developed into a chain, or strong analysis with NO evaluation. One report warned that good analysis with no evaluation could only be given 1 mark out of 6 on an Evaluate question.</p>\n<p>✅ <strong>Level 3 (5–6 marks):</strong> Chains of reasoning built on the case study''s own numbers (\"cutting the price from £25 to £20 raises revenue by £1,500...\") plus, for Evaluate, a judgement that takes a side and supports it (\"Overall, PED matters most here because...\").</p>\n<h4>Two topic-specific traps</h4>\n<ul>\n<li>\"Using a diagram\" means it — answers with <strong>no correct diagram are capped at 4/6</strong>.</li>\n<li>A <strong>movement along the demand curve</strong> can only happen after the <strong>supply curve shifts</strong> — many candidates missed this on the Plumwith Holidays question.</li>\n</ul>", "question": "An Evaluate 6-marker answer has two brilliant chains of analysis but no judgement or counter-view. Its likely score is...", "options": ["5 marks", "1–2 marks", "4 marks guaranteed", "6 marks"]}'::jsonb, '{"answer": 1, "explain": "The examiner report: candidates ''unable to evaluate the analysis they had provided... were unable to be given more than 1 mark out of 6''. Evaluation is not optional."}'::jsonb),
('economics:2-2-demand:fib:1aa7ceee', 'economics', 'economics:2-2-demand', '2.2 Demand', 'fib', 'fib', 2, '{"question": "Demand is the willingness and ___B1___ of consumers to buy a good at a given ___B2___ in a given period of time.", "blankOptions": {"B1": ["substitute", "supply", "complement", "ability"], "B2": ["price", "revenue", "willingness", "supply"]}}'::jsonb, '{"blanks": {"B1": "ability", "B2": "price"}}'::jsonb),
('economics:2-2-demand:fib:2ab7e7ff', 'economics', 'economics:2-2-demand', '2.2 Demand', 'fib', 'fib', 2, '{"question": "A change in the price of the good itself causes a ___B1___ along the demand curve. A change in any other factor causes a ___B2___ of the whole curve.", "blankOptions": {"B1": ["adding", "profit", "ability", "movement"], "B2": ["adding", "shift", "price", "willingness"]}}'::jsonb, '{"blanks": {"B1": "movement", "B2": "shift"}}'::jsonb),
('economics:2-2-demand:fib:dd7d7d82', 'economics', 'economics:2-2-demand', '2.2 Demand', 'fib', 'fib', 2, '{"question": "Market demand is found by ___B1___ together all the individual demands. The demand for workers is called ___B2___ demand because it comes from demand for the products they make.", "blankOptions": {"B1": ["adding", "shift", "elastic", "supply"], "B2": ["supply", "derived", "willingness", "price"]}}'::jsonb, '{"blanks": {"B1": "adding", "B2": "derived"}}'::jsonb),
