('economics:2-2-demand:match:42e2050f', 'economics', 'economics:2-2-demand', '2.2 Demand', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Complementary goods”?", "options": ["Percentage change in quantity demanded divided by percentage change in price", "All the individual demands for a product added together", "Demand for one thing (like workers) that comes from demand for something else (the product they make)", "Products bought and used together, like consoles and games"]}'::jsonb, '{"answer": 3, "explain": "“Complementary goods” means: Products bought and used together, like consoles and games"}'::jsonb),
('economics:2-2-demand:match:9f6aa353', 'economics', 'economics:2-2-demand', '2.2 Demand', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price elasticity of demand”?", "options": ["Quantity demanded changes by a bigger percentage than price — drawn as a flat curve", "A rise in quantity demanded caused by a fall in price", "All the individual demands for a product added together", "Percentage change in quantity demanded divided by percentage change in price"]}'::jsonb, '{"answer": 3, "explain": "“Price elasticity of demand” means: Percentage change in quantity demanded divided by percentage change in price"}'::jsonb),
('economics:2-2-demand:match:6ff0f8bd', 'economics', 'economics:2-2-demand', '2.2 Demand', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price elastic demand”?", "options": ["The willingness and ability to buy a good or service at a given price in a given time period", "Price multiplied by quantity sold", "Quantity demanded changes by a bigger percentage than price — drawn as a flat curve", "Products bought and used together, like consoles and games"]}'::jsonb, '{"answer": 2, "explain": "“Price elastic demand” means: Quantity demanded changes by a bigger percentage than price — drawn as a flat curve"}'::jsonb),
